var iconMap = {
  'laptop': '💻',
  'macbook': '💻',
  'desktop pc': '🖥️',
  'all-in-one pc': '🖥️',
  'server': '🗄️',
  'monitor': '🖥️',
  'tv / display panel': '📺',
  'mobile phone': '📱',
  'tablet': '📱',
  'printer': '🖨️',
  'scanner': '🖨️',
  'network switch': '🔌',
  'router': '🔌',
  'firewall appliance': '🔒',
  'wireless access point': '📡',
  'hard drive (hdd)': '💾',
  'external storage device': '💾',
  'nas / san storage': '💾',
  'ups': '🔋',
  'docking station': '🔌',
  'keyboard': '⌨️',
  'mouse': '🖱️',
  'headset': '🎧',
  'webcam': '📷',
  'projector': '📽️',
  'server rack': '🗄️',
  'barcode scanner': '📷',
  'gaming console': '🎮',
  'smartwatch / wearable': '⌚',
  'thin client': '💻',
  'pos terminal': '💳',
  'iot device': '📡',
  'cables & accessories': '🔌'
};
function getIcon(name) {
  if (!name) return '📦';
  return iconMap[name.toLowerCase()] || '📦';
}
function render(model) {
  var data = model && model.assets ? model.assets : [];
  var grid = document.getElementById('grid');
  if (!data.length) {
    grid.innerHTML = '<div class="empty">No asset data found</div>';
    return;
  }
  grid.innerHTML = data.map(function (r) {
    return '<div class="card">' + '<div class="card-top">' + '<div class="icon">' + getIcon(r.item_type_name) + '</div>' + '<div class="type-name">' + (r.item_type_name || '—') + '</div>' + '</div>' + '<div class="total">' + (r.total || 0) + '</div>' + '<div class="stats">' + '<div class="stat"><span class="stat-label">Month</span><span class="stat-value">' + (r.this_month || 0) + '</span></div>' + '<div class="stat"><span class="stat-label">Year</span><span class="stat-value">' + (r.this_year || 0) + '</span></div>' + '</div>' + '</div>';
  }).join('');
}
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function () {
  render(appsmith.model);
});

